import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaUserMd, 
  FaPills, 
  FaEye, 
  FaEyeSlash, 
  FaSpinner, 
  FaHeartbeat,
  FaChevronDown,
  FaInfoCircle,
  FaGlobe
} from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t, i18n } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // role, credentials
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [language, setLanguage] = useState('en');
  const [error, setError] = useState('');
  const [showCredentials, setShowCredentials] = useState(false);

  const roles = [
    {
      id: 'patient',
      name: t('patient') || 'Patient',
      icon: FaUser,
      gradient: 'from-blue-500 to-blue-600',
      bgColor: 'bg-blue-50',
      borderColor: 'border-blue-200',
      hoverBg: 'hover:bg-blue-100',
      textColor: 'text-blue-700',
      description: 'Access medical consultations and health records',
      usernamePrefix: 'p',
      sampleUsername: 'p001'
    },
    {
      id: 'doctor',
      name: t('doctor') || 'Doctor',
      icon: FaUserMd,
      gradient: 'from-green-500 to-green-600',
      bgColor: 'bg-green-50',
      borderColor: 'border-green-200',
      hoverBg: 'hover:bg-green-100',
      textColor: 'text-green-700',
      description: 'Manage appointments and patient consultations',
      usernamePrefix: 'd',
      sampleUsername: 'd001'
    },
    {
      id: 'pharmacist',
      name: t('pharmacist') || 'Pharmacist',
      icon: FaPills,
      gradient: 'from-purple-500 to-purple-600',
      bgColor: 'bg-purple-50',
      borderColor: 'border-purple-200',
      hoverBg: 'hover:bg-purple-100',
      textColor: 'text-purple-700',
      description: 'Manage prescriptions and medicine inventory',
      usernamePrefix: 'pm',
      sampleUsername: 'pm001'
    }
  ];

  const languages = [
    { code: 'en', name: 'English', flag: '🇺🇸' },
    { code: 'hi', name: 'हिंदी', flag: '🇮🇳' },
    { code: 'pa', name: 'ਪੰਜਾਬੀ', flag: '🇮🇳' }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      console.log('🔐 Attempting login with:', { username, role: selectedRole });
      
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          username: username,
          password: password
        })
      });
      
      console.log('📡 Response status:', response.status);
      
      const data = await response.json();
      console.log('📋 Response data:', data);
      
      if (response.ok) {
        // Store token in localStorage
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        
        console.log('✅ Login successful, redirecting...');
        
        // Call onLogin with user data
        onLogin({
          ...data.user,
          token: data.token
        });
      } else {
        console.error('❌ Login failed:', data);
        setError(data.message || 'Login failed');
      }
    } catch (err) {
      console.error('🚨 Login error:', err);
      if (err.name === 'TypeError' && err.message.includes('fetch')) {
        setError('Unable to connect to server. Please ensure the backend is running on http://localhost:5000');
      } else {
        setError('Network error. Please check your connection and try again.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const changeLanguage = (langCode) => {
    setLanguage(langCode);
    i18n.changeLanguage(langCode);
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch(role) {
      case 'patient': return 'patient123';
      case 'doctor': return 'doctor123';
      case 'pharmacist': return 'pharmacy123';
      default: return '';
    }
  };

  const fillSampleCredentials = () => {
    const role = getCurrentRole();
    if (role) {
      setUsername(role.sampleUsername);
      setPassword(getPasswordForRole(selectedRole));
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-green-50 relative overflow-hidden">
      {/* Enhanced Background Pattern */}
      <div className="absolute inset-0 opacity-10">
        <div className="absolute top-20 left-20 w-96 h-96 bg-gradient-to-r from-blue-400 to-indigo-500 rounded-full mix-blend-multiply filter blur-xl animate-pulse"></div>
        <div className="absolute top-40 right-20 w-80 h-80 bg-gradient-to-r from-green-400 to-emerald-500 rounded-full mix-blend-multiply filter blur-xl animate-pulse delay-1000"></div>
        <div className="absolute bottom-20 left-1/2 w-72 h-72 bg-gradient-to-r from-purple-400 to-violet-500 rounded-full mix-blend-multiply filter blur-xl animate-pulse delay-2000"></div>
        <div className="absolute top-1/2 left-10 w-48 h-48 bg-gradient-to-r from-pink-300 to-rose-400 rounded-full mix-blend-multiply filter blur-xl animate-pulse delay-3000"></div>
      </div>
      
      {/* Floating Medical Icons */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 opacity-5 animate-float">
          <FaHeartbeat className="text-6xl text-red-400" />
        </div>
        <div className="absolute top-3/4 right-1/4 opacity-5 animate-float-delayed">
          <FaPills className="text-5xl text-purple-400" />
        </div>
        <div className="absolute top-1/2 right-1/3 opacity-5 animate-float-slow">
          <FaUserMd className="text-4xl text-green-400" />
        </div>
      </div>

      <div className="relative z-10 min-h-screen flex items-center justify-center p-4">
        <div className="w-full max-w-lg">
          {/* Language Selector */}
          <div className="mb-8 flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm rounded-2xl p-2 shadow-lg border border-white/20">
              <div className="flex items-center gap-2">
                <FaGlobe className="text-gray-500 ml-2" />
                {languages.map((lang) => (
                  <button
                    key={lang.code}
                    onClick={() => changeLanguage(lang.code)}
                    className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                      language === lang.code
                        ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white shadow-lg transform scale-105'
                        : 'text-gray-600 hover:bg-blue-50 hover:scale-105'
                    }`}
                  >
                    <span>{lang.flag}</span>
                    <span>{lang.name}</span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Enhanced Logo and Title */}
          <div className="text-center mb-12">
            <div className="relative mx-auto mb-8 w-32 h-32">
              {/* Multiple Shadow Layers for Depth */}
              <div className="absolute inset-2 bg-gradient-to-r from-blue-600 to-green-500 rounded-3xl shadow-2xl transform rotate-6 opacity-20"></div>
              <div className="absolute inset-1 bg-gradient-to-r from-blue-500 to-green-500 rounded-3xl shadow-xl transform rotate-3 opacity-40"></div>
              <div className="relative bg-gradient-to-r from-blue-600 to-green-600 rounded-3xl flex items-center justify-center w-full h-full shadow-2xl border-4 border-white transform hover:scale-110 transition-transform duration-300">
                <FaHeartbeat className="text-white text-4xl animate-pulse" />
              </div>
              {/* Glowing Ring Effect */}
              <div className="absolute inset-0 rounded-3xl bg-gradient-to-r from-blue-400 to-green-400 opacity-30 blur-md animate-pulse"></div>
            </div>
            <h1 className="text-5xl font-bold bg-gradient-to-r from-blue-700 via-blue-600 to-green-600 bg-clip-text text-transparent mb-4 tracking-tight">
              Helio
            </h1>
            <div className="space-y-2">
              <p className="text-gray-700 text-xl font-semibold">Bringing Healthcare Closer to You</p>
              <div className="flex items-center justify-center gap-2 text-gray-600">
                <span className="w-2 h-2 bg-red-400 rounded-full animate-pulse"></span>
                <p className="text-base font-medium">Rural Healthcare • Punjab, India</p>
                <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse delay-500"></span>
              </div>
            </div>
          </div>

          <div className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-2xl border border-white/30 overflow-hidden relative">
            {/* Subtle Header Gradient */}
            <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-blue-500 via-purple-500 to-green-500"></div>
            {/* Step 1: Role Selection */}
            {step === 'role' && (
              <div className="p-8">
                <div className="text-center mb-8">
                  <h2 className="text-2xl font-bold text-gray-800 mb-2">Choose Your Role</h2>
                  <p className="text-gray-600">Select how you'd like to access Helio</p>
                </div>
                
                <div className="space-y-5 mb-8">
                  {roles.map((role) => {
                    const IconComponent = role.icon;
                    return (
                      <button
                        key={role.id}
                        onClick={() => handleRoleSelect(role.id)}
                        className={`w-full p-7 border-2 ${role.borderColor} ${role.bgColor} rounded-2xl ${role.hoverBg} transition-all duration-300 transform hover:scale-105 hover:shadow-2xl hover:-translate-y-1 group relative overflow-hidden`}
                      >
                        {/* Subtle shine effect on hover */}
                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent transform -skew-x-12 -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                        
                        <div className="flex items-center gap-6 relative z-10">
                          <div className={`w-20 h-20 bg-gradient-to-r ${role.gradient} rounded-2xl flex items-center justify-center shadow-lg group-hover:shadow-xl transition-all duration-300 group-hover:scale-110 relative`}>
                            <IconComponent className="text-white text-3xl" />
                            {/* Icon glow effect */}
                            <div className="absolute inset-0 rounded-2xl bg-white/20 opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                          </div>
                          <div className="text-left flex-1">
                            <h3 className={`font-bold text-xl ${role.textColor} mb-2 group-hover:text-opacity-90`}>{role.name}</h3>
                            <p className="text-gray-700 text-sm mb-3 leading-relaxed">{role.description}</p>
                            <div className="flex items-center gap-3">
                              <span className="text-xs bg-white/80 px-3 py-1.5 rounded-full text-gray-700 font-medium border border-white/50">
                                Sample: {role.sampleUsername}
                              </span>
                              <div className="flex items-center gap-1">
                                <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
                                <span className="text-xs text-green-600 font-medium">Available</span>
                              </div>
                            </div>
                          </div>
                          {/* Arrow indicator */}
                          <div className="text-gray-400 group-hover:text-gray-600 transition-colors">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                            </svg>
                          </div>
                        </div>
                      </button>
                    );
                  })}
                </div>
                
                {/* Enhanced Demo Credentials Info */}
                <div className="border-t border-gray-100 pt-6">
                  <button
                    onClick={() => setShowCredentials(!showCredentials)}
                    className="w-full flex items-center justify-between p-5 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-2xl hover:from-blue-100 hover:to-indigo-100 transition-all duration-300 border border-blue-100 group"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-gradient-to-r from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center">
                        <FaInfoCircle className="text-white text-lg" />
                      </div>
                      <div className="text-left">
                        <span className="font-bold text-blue-800 text-lg">Demo Credentials</span>
                        <p className="text-blue-600 text-sm">Click to view sample login details</p>
                      </div>
                    </div>
                    <FaChevronDown className={`text-blue-600 transition-transform duration-300 ${showCredentials ? 'rotate-180' : ''} group-hover:scale-110`} />
                  </button>
                  
                  {showCredentials && (
                    <div className="mt-5 p-6 bg-gradient-to-br from-blue-50 via-white to-green-50 rounded-2xl border-l-4 border-blue-400 shadow-inner">
                      <div className="space-y-4 text-sm">
                        <div className="flex justify-between items-center p-3 bg-white/70 rounded-xl border border-blue-100">
                          <div className="flex items-center gap-3">
                            <span className="text-2xl">👤</span>
                            <span className="font-bold text-blue-700">Patients:</span>
                          </div>
                          <span className="text-gray-800 font-mono bg-gray-100 px-3 py-1 rounded-lg">p001, p002, p003</span>
                        </div>
                        <div className="flex justify-between items-center p-3 bg-white/70 rounded-xl border border-green-100">
                          <div className="flex items-center gap-3">
                            <span className="text-2xl">👨‍⚕️</span>
                            <span className="font-bold text-green-700">Doctors:</span>
                          </div>
                          <span className="text-gray-800 font-mono bg-gray-100 px-3 py-1 rounded-lg">d001, d002, d003</span>
                        </div>
                        <div className="flex justify-between items-center p-3 bg-white/70 rounded-xl border border-purple-100">
                          <div className="flex items-center gap-3">
                            <span className="text-2xl">💊</span>
                            <span className="font-bold text-purple-700">Pharmacists:</span>
                          </div>
                          <span className="text-gray-800 font-mono bg-gray-100 px-3 py-1 rounded-lg">pm001, pm002, pm003</span>
                        </div>
                        <div className="mt-5 pt-4 border-t border-gray-200 bg-gradient-to-r from-yellow-50 to-amber-50 p-4 rounded-xl border border-yellow-200">
                          <div className="flex items-center gap-3 mb-2">
                            <span className="text-xl">🔐</span>
                            <strong className="text-amber-800">Default Passwords:</strong>
                          </div>
                          <div className="grid grid-cols-1 gap-2 text-xs">
                            <span className="font-mono bg-white/70 px-3 py-2 rounded-lg border">Patient: <strong>patient123</strong></span>
                            <span className="font-mono bg-white/70 px-3 py-2 rounded-lg border">Doctor: <strong>doctor123</strong></span>
                            <span className="font-mono bg-white/70 px-3 py-2 rounded-lg border">Pharmacist: <strong>pharmacy123</strong></span>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Step 2: Enhanced Login Credentials */}
            {step === 'credentials' && (
              <div className="p-8">
                <div className="text-center mb-10">
                  <div className={`w-24 h-24 bg-gradient-to-r ${getCurrentRole()?.gradient} rounded-3xl mx-auto mb-6 flex items-center justify-center shadow-2xl relative group`}>
                    {React.createElement(getCurrentRole()?.icon, { className: "text-white text-4xl group-hover:scale-110 transition-transform duration-300" })}
                    {/* Rotating border effect */}
                    <div className="absolute inset-0 rounded-3xl bg-gradient-to-r from-white/20 to-transparent animate-spin-slow opacity-50"></div>
                  </div>
                  <h2 className="text-3xl font-bold text-gray-800 mb-2">{getCurrentRole()?.name} Login</h2>
                  <p className="text-gray-600 text-lg">Enter your credentials to continue</p>
                  <div className="mt-3 inline-flex items-center gap-2 px-4 py-2 bg-gray-100 rounded-full">
                    <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
                    <span className="text-sm text-gray-600 font-medium">Secure Login</span>
                  </div>
                </div>

                {error && (
                  <div className="mb-8 p-5 bg-gradient-to-r from-red-50 to-pink-50 border-l-4 border-red-400 rounded-2xl shadow-lg">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center flex-shrink-0">
                        <span className="text-red-600 text-lg font-bold">!</span>
                      </div>
                      <div>
                        <p className="text-red-800 font-semibold">Authentication Error</p>
                        <p className="text-red-700 text-sm mt-1">{error}</p>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-8">
                  <div className="space-y-3">
                    <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">
                      Username
                    </label>
                    <div className="relative">
                      <input
                        type="text"
                        value={username}
                        onChange={(e) => setUsername(e.target.value)}
                        placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                        className="w-full px-5 py-4 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all text-lg bg-white/80 backdrop-blur-sm hover:border-gray-300"
                        disabled={isLoading}
                      />
                      <div className="absolute right-4 top-1/2 transform -translate-y-1/2">
                        <FaUser className="text-gray-400" />
                      </div>
                    </div>
                  </div>

                  <div className="space-y-3">
                    <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">
                      Password
                    </label>
                    <div className="relative">
                      <input
                        type={showPassword ? 'text' : 'password'}
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="Enter your password"
                        className="w-full px-5 py-4 pr-14 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all text-lg bg-white/80 backdrop-blur-sm hover:border-gray-300"
                        disabled={isLoading}
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-500 hover:text-gray-700 transition-colors p-1 rounded-lg hover:bg-gray-100"
                      >
                        {showPassword ? <FaEyeSlash size={20} /> : <FaEye size={20} />}
                      </button>
                    </div>
                  </div>

                  {/* Enhanced Quick Fill Demo */}
                  <div className="p-5 bg-gradient-to-br from-gray-50 via-blue-50 to-indigo-50 rounded-2xl border-2 border-dashed border-blue-200 hover:border-blue-300 transition-colors">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm font-semibold text-gray-700 mb-1">Quick Demo Fill</p>
                        <p className="text-xs text-gray-600">Auto-fill with sample credentials</p>
                      </div>
                      <button
                        onClick={fillSampleCredentials}
                        className="px-4 py-2 bg-gradient-to-r from-blue-500 to-indigo-600 text-white rounded-xl font-medium hover:from-blue-600 hover:to-indigo-700 transition-all transform hover:scale-105 shadow-lg hover:shadow-xl disabled:opacity-50 disabled:transform-none"
                        disabled={isLoading}
                      >
                        Fill ({getCurrentRole()?.sampleUsername})
                      </button>
                    </div>
                  </div>

                  <div className="flex gap-4 pt-6">
                    <button
                      onClick={handleBack}
                      className="flex-1 py-4 px-6 border-2 border-gray-300 rounded-2xl text-gray-700 font-bold hover:bg-gray-50 hover:border-gray-400 transition-all transform hover:scale-105 flex items-center justify-center gap-2"
                      disabled={isLoading}
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                      </svg>
                      Back
                    </button>
                    <button
                      onClick={handleLogin}
                      disabled={isLoading || !username || !password}
                      className="flex-1 py-4 px-6 bg-gradient-to-r from-blue-500 via-blue-600 to-indigo-600 text-white rounded-2xl font-bold hover:from-blue-600 hover:via-blue-700 hover:to-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all transform hover:scale-105 flex items-center justify-center gap-3 shadow-xl hover:shadow-2xl relative overflow-hidden"
                    >
                      {/* Button shine effect */}
                      <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent transform -skew-x-12 -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                      {isLoading ? (
                        <>
                          <FaSpinner className="animate-spin text-xl" />
                          Logging in...
                        </>
                      ) : (
                        <>
                          <span>Login</span>
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5-5 5M6 12h12" />
                          </svg>
                        </>
                      )}
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Enhanced Footer */}
          <div className="text-center mt-10">
            <div className="inline-flex items-center gap-3 px-6 py-3 bg-white/70 backdrop-blur-sm rounded-full shadow-lg border border-white/30 hover:bg-white/80 transition-all duration-300">
              <FaHeartbeat className="text-red-500 animate-pulse text-lg" />
              <span className="text-sm text-gray-700 font-semibold">Healthcare Access</span>
              <span className="w-1 h-1 bg-gray-400 rounded-full"></span>
              <span className="text-sm text-gray-600 font-medium">Nabha, Punjab</span>
            </div>
            <p className="text-xs text-gray-500 mt-4 font-medium">Secure • Reliable • Accessible</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
